#include <stdio.h>
#include <stdlib.h>
#include <limits.h>

int cmp(const void *a, const void *b) {
    long long x = *(const long long *)a;
    long long y = *(const long long *)b;
    return (x > y) - (x < y);
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        long long *a = (long long*)malloc(N * sizeof(long long));
        for (int i = 0; i < N; ++i) scanf("%lld", &a[i]);
        qsort(a, N, sizeof(long long), cmp);
        long long best = LLONG_MAX;
        for (int j = 1; j <= N-2 && best!=0; ++j) {
            int i = j-1, k = j+1;
            while (i >= 0 && k < N) {
                long long cur = a[i] + a[k] - 2LL * a[j];
                long long ab = cur >= 0 ? cur : -cur;
                if (ab < best) best = ab;
                if (best == 0) break;
                if (cur < 0) ++k; else --i;
            }
        }
        printf("%lld\n", best);
        free(a);
    }
    return 0;
}

