import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        a = [int(next(it)) for _ in range(N)]
        a.sort()
        best = 10**20
        for j in range(1, N-1):
            i, k = j-1, j+1
            while i >= 0 and k < N:
                cur = a[i] + a[k] - 2*a[j]
                ab = cur if cur >= 0 else -cur
                if ab < best:
                    best = ab
                if best == 0:
                    break
                if cur < 0:
                    k += 1
                else:
                    i -= 1
            if best == 0:
                break
        out_lines.append(str(best))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

